1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_PRICE = 60;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	function calculateItemPremium(item: any): number {
14	  const base = BASE_PREMIUMS[item.type];
15	  let premium = base;
16	  if (item.cursed) {
17	    premium += base * 0.5;
18	  }
19	  if (item.enchantment >= 5) {
20	    premium += base * 0.3;
21	  }
22	  return premium;
23	}
24	
25	export function claimOffice(input: any): unknown {
26	  const results: unknown[] = [];
27	  let quoteIndex = 0;
28	
29	  for (const step of input.steps) {
30	    if (step.op === "claim") {
31	      results.push({ payout: 0, remainingCap: 0 });
32	      continue;
33	    }
34	    const items = step.items;
35	    let itemsTotal = 0;
36	    let policyBase = 0;
37	
38	    const typeCounts: Record<string, number> = {};
39	    for (const item of items) {
40	      itemsTotal += calculateItemPremium(item);
41	      policyBase += BASE_PREMIUMS[item.type];
42	      typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
43	    }
44	
45	    for (const type in typeCounts) {
46	      if (typeCounts[type] === 3) {
47	        itemsTotal = itemsTotal - (3 * BASE_PREMIUMS[type]) + BLOCK_OF_THREE_PRICE;
48	      }
49	    }
50	
51	    let policyModifier = 0;
52	    if (input.customer.yearsWithMHPCO >= 2) {
53	      policyModifier -= policyBase * 0.2;
54	    }
55	    policyModifier += policyBase * 0.1;
56	    if (quoteIndex > 0) {
57	      policyModifier -= policyBase * 0.15;
58	    }
59	
60	    const premium = Math.ceil(itemsTotal + policyModifier + PROCESSING_FEE);
61	    results.push({ premium });
62	    quoteIndex++;
63	  }
64	
65	  return { results };
66	}
